/**
 * The Void — Boss Engine Tests
 *
 * Verifies ICE knot combat mechanics:
 * - Solos are crushed by wave scaling
 * - Groups can survive and extract the void
 * - Stealing void is tied to player HEX and Phyle richness
 * - Dynamic difficulty based on β₁ and popularity
 */

import { describe, it, expect } from 'vitest';
import { initiateKnotEncounter, tickKnotEncounter, tickIdleKnotEncounter } from '../void-knot-engine';
import { DIMENSION_TIME_DILATION } from '../void-game-types';
import type { ObserverState, PhyleName } from '../void-game-types';

describe('void-boss-engine', () => {
  const mockPlayer: ObserverState = {
    did: 'test',
    coordinate: { seed: 1, dimension: 3, hexQ: 0, hexR: 0, hexS: 0, tick: 1 },
    energy: 500, // Decent stamina
    majorPhyle: 'hacker' as unknown as PhyleName,
    minorPhyle: 'builder' as unknown as PhyleName,
    particleType: 'dps',
    totalFailures: 10,
    totalSuccesses: 5,
    wisdom: 10,
    ploSinceLastFailure: 0,
    highestDimension: 3,
    cycleCount: 0,
    sliver: 0,
    activeKnotEncounter: null,
  };

  describe('initiateKnotEncounter', () => {
    it('scales knot complexity with β₁ and popularity', () => {
      const dim3 = initiateKnotEncounter(3, 'scientist', 1.0, 1);
      const dim9 = initiateKnotEncounter(9, 'scientist', 1.0, 1);
      
      // Dim 9 β₁ is 55, Dim 3 is 3
      expect(dim9.maxKnotComplexity).toBeGreaterThan(dim3.maxKnotComplexity);
      
      const richPhyle = initiateKnotEncounter(3, 'hedonist', 2.5, 1);
      expect(richPhyle.maxKnotComplexity).toBe(dim3.maxKnotComplexity * 2.5);
    });
  });

  describe('tickKnotEncounter', () => {
    it('allows a solo player to extract void but take damage', () => {
      const boss = initiateKnotEncounter(3, 'scientist', 1.0, 1);
      const result = tickKnotEncounter(boss, mockPlayer);
      
      expect(result.voidStolen).toBeGreaterThan(0);
      expect(result.energyRadiated).toBeGreaterThan(0);
      expect(result.knotState.knotComplexity).toBeLessThan(boss.knotComplexity);
      expect(result.knotState.ticksElapsed).toBe(1);
    });

    it('wave damage increases over time (forced vulnerability)', () => {
      let boss = initiateKnotEncounter(3, 'scientist', 1.0, 1);
      const firstTick = tickKnotEncounter(boss, mockPlayer);
      
      // Fast forward 50 ticks to simulate a prolonged fight
      boss = { ...firstTick.knotState, ticksElapsed: 50 };
      const lateTick = tickKnotEncounter(boss, mockPlayer);
      
      // Damage should be significantly higher due to time scaling
      expect(lateTick.energyRadiated).toBeGreaterThan(firstTick.energyRadiated);
    });

    it('void extraction slows down as player HEX depletes', () => {
      const boss = initiateKnotEncounter(3, 'scientist', 1.0, 1);
      
      const healthyPlayer = { ...mockPlayer, energy: 1000 };
      const healthyTick = tickKnotEncounter(boss, healthyPlayer);
      
      const dyingPlayer = { ...mockPlayer, energy: 20 };
      const dyingTick = tickKnotEncounter(boss, dyingPlayer);
      
      // Healthy player with more stamina extracts topology faster
      expect(healthyTick.voidStolen).toBeGreaterThan(dyingTick.voidStolen);
    });

    it('supports massively distributed attacks (N players)', () => {
      // Create a massive Boss (Dim 9, highly popular)
      const massiveBoss = initiateKnotEncounter(9, 'builder', 3.0, 1000); // 1000 players hacking
      
      // The wave intensity is huge (BASE_WAVE_DAMAGE * 55 * time)
      // But divided by 1000 participants
      const result = tickKnotEncounter(massiveBoss, mockPlayer);
      
      // A solo player would take ~275+ base damage, and die immediately.
      // With 1000 players, the distributed wave damage should be tiny.
      expect(result.energyRadiated).toBeLessThan(10);
      
      // And they still extract topology based on the popularity multiplier
      expect(result.voidStolen).toBeGreaterThan(0);
    });
  });

  describe('tickIdleKnotEncounter (Skyrms Equilibrium)', () => {
    it('leaks knowledge (spillover) when participants = 0', () => {
      const boss = initiateKnotEncounter(3, 'scientist', 1.0, 0); // 0 participants
      
      const idleResult = tickIdleKnotEncounter(boss);
      
      // The knot decays on its own (spillover)
      expect(idleResult.voidSpilled).toBeGreaterThan(0);
      expect(idleResult.knotState.knotComplexity).toBeLessThan(boss.knotComplexity);
      
      // Wave intensity cools down
      expect(idleResult.knotState.systemicEntropy).toBeLessThanOrEqual(boss.systemicEntropy);
    });

    it('throws if called while participants are active', () => {
      const activeBoss = initiateKnotEncounter(3, 'scientist', 1.0, 1);
      expect(() => tickIdleKnotEncounter(activeBoss)).toThrow();
    });
  });
});
